table = _lcs(x, y)

def _reconstruct(i, j):
    if i == 0 or j == 0:
        return []
    if x[i - 1] == y[j - 1]:
        return _reconstruct(i - 1, j - 1) + [x[i - 1]]
    if table[i - 1, j] >= table[i, j - 1]:
        return _reconstruct(i - 1, j)
    return _reconstruct(i, j - 1)

return _reconstruct(len(x), len(y))

