async def peek(self, size=-1):
    if size is None or size < 0:
        size = self._buffer_len - self._buffer_pos

    if size == 0:
        return b''

    if self._buffer_pos > 0:
        self._trim_buffer()

    while not self._exhausted and (self._buffer_len - self._buffer_pos) < size:
        try:
            chunk = await self._source.__anext__()
        except StopAsyncIteration:
            self._exhausted = True
            break

        if self._buffer_len > self._buffer_pos:
            self._buffer += chunk
            self._buffer_len += len(chunk)
        else:
            self._buffer = chunk
            self._buffer_len = len(chunk)
            self._buffer_pos = 0

    end = self._buffer_pos + size
    return self._buffer[self._buffer_pos:end]

async def read_until(self, delimiter, size=-1, consume_delimiter=False):
    if size is not None and size >= 0:
        async for chunk in self._iter_delimited(delimiter, size_hint=size):
            return await self._read_from([chunk], size)
    else:
        async for chunk in self._iter_delimited(delimiter):
            return await self._read_from([chunk], -1)

    if consume_delimiter:
        await self._consume_delimiter(delimiter)

    return b''

