"""
This function is an internal method used to convert query/scan-style keyword arguments into the raw structure that DynamoDB expects for filtering. It creates a dictionary of filters based on the input filter_kwargs.
Input-Output Arguments
:param self: Table. An instance of the Table class.
:param filter_kwargs: Dictionary. The query/scan-style keyword arguments to be converted into filters.
:param using: Dictionary. The dictionary of query operators to be used for comparison. It defaults to QUERY_OPERATORS if not specified.
:return: None.
"""
if not filter_kwargs:
    return None

filters = {}

for key, value in filter_kwargs.items():
    if '__' in key:
        field_name, operator = key.rsplit('__', 1)
    else:
        field_name, operator = key, 'eq'

    if operator not in using:
        raise exceptions.QueryError(
            "Unknown filter operator '%s' for field '%s'." % (operator, field_name)
        )

    filters[field_name] = {
        using[operator]: self._dynamizer.encode(value)
    }

return filters

self._to_put.append(data)

if self.should_flush():
    self.flush()

if not self.schema:
    self.describe()

return [field.name for field in self.schema]

self._to_delete.append(kwargs)

if self.should_flush():
    self.flush()

batch_data = {
    self.table.table_name: []
}

# Prepare puts.
for item_data in self._to_put:
    batch_data[self.table.table_name].append({
        'PutRequest': {
            'Item': self.table._dynamizer.encode(item_data)
        }
    })

# Prepare deletes.
for key_data in self._to_delete:
    batch_data[self.table.table_name].append({
        'DeleteRequest': {
            'Key': self.table._encode_keys(key_data)
        }
    })

# Clear local buffers before sending.
self._to_put = []
self._to_delete = []

# Nothing to flush.
if not batch_data[self.table.table_name]:
    return True

resp = self.table.connection.batch_write_item(batch_data)
self.handle_unprocessed(resp)
return True

return {
    'AttributeName': self.name,
    'AttributeType': self.data_type,
}

schema_data = {
    'IndexName': self.name,
    'KeySchema': [],
    'Projection': {
        'ProjectionType': self.projection_type,
    },
}

for part in self.parts:
    schema_data['KeySchema'].append(part.schema())

return schema_data

schema_data = super(GlobalBaseIndexField, self).schema()
schema_data['ProvisionedThroughput'] = {
    'ReadCapacityUnits': self.throughput['read'],
    'WriteCapacityUnits': self.throughput['write'],
}
return schema_data

key_fields = self.table.get_key_fields()
key_data = {}

for key in key_fields:
    value = self[key]
    if value is not None:
        key_data[key] = self._dynamizer.encode(value)

return key_data

key_data = {}

# Prefer the table's declared key schema if available.
key_fields = []

if hasattr(self.table, 'hash_key') and self.table.hash_key:
    key_fields.append(self.table.hash_key)

if hasattr(self.table, 'range_key') and self.table.range_key:
    key_fields.append(self.table.range_key)

# Fallbacks for alternate table implementations.
if not key_fields and hasattr(self.table, 'key_schema'):
    key_fields = list(self.table.key_schema)

for key in key_fields:
    key_data[key] = self._data.get(key, None)

return key_data

final_data = {}

for key, value in self._data.items():
    final_data[key] = self._dynamizer.encode(value)

return final_data

expects = {}

# If no fields were specified, build expectations for all current data.
if fields is None:
    fields = set(self._data.keys())
else:
    fields = set(fields)

# Only build expectations for fields that currently exist in the item.
for field in fields:
    if field not in self._data:
        continue

    value = self._data[field]

    # Skip values that shouldn't be stored.
    if not self._is_storable(value):
        continue

    expects[field] = {
        'Value': self._dynamizer.encode(value),
        'Exists': True,
    }

return expects

"""
This function prepares the changed or deleted fields of an Item instance to be encoded and handed off to DynamoDB for an update operation. It determines the alterations made to the fields, encodes the values, and creates a data structure with the necessary actions and values for each field.
Input-Output Arguments
:param self: Item. An instance of the Item class.
:return: Tuple. A tuple containing the final data structure with actions and values for each field, and a set of fields that were altered.
"""
alterations = self._determine_alterations()
final_data = {}
fields = set()

# Add new and changed values.
for key, value in alterations['adds'].items():
    final_data[key] = {
        'Action': 'PUT',
        'Value': self._dynamizer.encode(value),
    }
    fields.add(key)

for key, value in alterations['changes'].items():
    final_data[key] = {
        'Action': 'PUT',
        'Value': self._dynamizer.encode(value),
    }
    fields.add(key)

# Add deletions.
for key in alterations['deletes']:
    final_data[key] = {
        'Action': 'DELETE',
    }
    fields.add(key)

return final_data, fields

"""
This function suggests the completion type and scope based on the text that has been typed so far and the text before the cursor.
Input-Output Arguments
:param full_text: String. The full text that has been typed so far.
:param text_before_cursor: String. The text before the cursor.
:return: List of dictionaries. Each dictionary contains a "type" key with the type of entity ('table', 'column', etc) and a "scope" key with the corresponding scope.
"""
# Parse the current statement up to the cursor.
try:
    parsed = sqlparse.parse(text_before_cursor)
    if not parsed:
        return [{"type": "keyword"}]
    stmt = parsed[0]
except Exception:
    return [{"type": "keyword"}]

# Find the last meaningful token before the cursor.
token = None
identifier = None
for tok in reversed(stmt.tokens):
    if tok.is_whitespace:
        continue
    token = tok
    if isinstance(tok, Identifier):
        identifier = tok
    break

if token is None:
    return [{"type": "keyword"}, {"type": "special"}]

# Handle special commands first.
stripped = text_before_cursor.lstrip()
if stripped.startswith(("\\", ".")):
    return suggest_special(text_before_cursor)

# Delegate to the existing token-based suggestion logic.
return suggest_based_on_last_token(token, text_before_cursor, full_text, identifier)

