async def suggest(self):
    columns = await self.get_columns(self.sql, self.params)
    row_count = await self.get_row_count()
    facet_size = self.get_facet_size()
    already_enabled = [c["config"]["simple"] for c in self.get_configs()]
    suggested_facets = []

    for column in columns:
        if column in already_enabled:
            continue

        suggested_facet_sql = """
            select {column} as value, count(*) as count
            from ({sql})
            where {column} is not null
            group by {column}
            order by count desc, value
            limit {limit}
        """.format(
            column=escape_sqlite(column),
            sql=self.sql,
            limit=facet_size + 1,
        )

        try:
            results = await self.ds.execute(
                self.database,
                suggested_facet_sql,
                self.params,
                truncate=False,
                custom_time_limit=self.ds.setting("facet_suggest_time_limit_ms"),
                log_sql_errors=False,
            )
            rows = results.rows
            distinct_count = len(rows)

            if (
                0 < distinct_count <= facet_size
                and distinct_count < row_count
                and any(row["count"] > 1 for row in rows)
            ):
                suggested_facets.append(
                    {
                        "name": column,
                        "type": "column",
                        "toggle_url": self.ds.absolute_url(
