    if sqla_14:
        assert dialect is not None
        return dialect.identifier_preparer.format_constraint(
            constraint, _alembic_quote=False
        )

    # SQLAlchemy < 1.4: emulate the final rendered name without quotes
    preparer = dialect.identifier_preparer if dialect is not None else None
    if preparer is not None:
        return preparer.format_constraint(constraint)
    else:
        return constraint.name

@_constraint_renderers.dispatch_for(sa_schema.CheckConstraint)
def _render_check_constraint(
    constraint: CheckConstraint,
    autogen_context: AutogenContext,
    namespace_metadata: Optional[MetaData],
) -> Optional[str]:
    rendered = _user_defined_render("check", constraint, autogen_context)
    if rendered is not False:
        return rendered

    # If this CHECK constraint is generated implicitly by a type already
    # present on the parent column, don't render it separately.
    if constraint._create_rule is not None and constraint.columns:
        parent = list(constraint.columns)[0]
        if parent is not None and getattr(parent, "type", None) is not None:
            if sqla_compat._type_has_check_constraint(parent.type):
                return None

    opts = []
    if constraint.name:
        opts.append(
            ("name", repr(_render_gen_name(autogen_context, constraint.name)))
        )

    sqltext = _render_potential_expr(
        constraint.sqltext, autogen_context, wrap_in_text=False
    )

    return "%(prefix)sCheckConstraint(%(sqltext)s%(args)s)" % {
        "prefix": _sqlalchemy_autogenerate_prefix(autogen_context),
        "sqltext": sqltext,
        "args": (
            ", " + ", ".join("%s=%s" % (kwname, val) for kwname, val in opts)
            if opts
