    candidates.append((triplet(base), 0, 3))
    candidates.append((quintuplet(base), 0, 5))
    candidates.append((septuplet(base, True), 0, 7))
    candidates.append((septuplet(base, False), 0, 7))

# Find the closest match within a small tolerance.
best = None
best_diff = None
for candidate_value, nr_dots, ratio in candidates:
    diff = abs(candidate_value - value)
    if best is None or diff < best_diff:
        best = (candidate_value, nr_dots, ratio)
        best_diff = diff

