# Otherwise, fall back to the nearest base value with no dots/ratio.
if best is not None:
    candidate_value, nr_dots, ratio = best
    if ratio != 1:
        # For tuplets, return the base note value that generated it.
        # Since we only need to report the parts, use the closest base.
        for base in base_values:
            if abs((ratio * base) / float(1 if ratio == 1 else (4 if ratio == 7 and candidate_value in (septuplet(base, True),) else 1)) - candidate_value) < 1e-9:
                return (base, nr_dots, ratio)
