@classmethod
def parse(cls, ls):
    # type: (Text) -> Permissions

    """
    This function parses permissions in Linux notation and returns an instance of the Permissions class with the parsed permissions.
    Input-Output Arguments
    :param cls: Class. The class object of the Permissions class.
    :param ls: Text. The string containing the permissions in Linux notation.
    :return: Permissions. An instance of the Permissions class with the parsed permissions.
    """
    if not isinstance(ls, six.string_types):
        raise ValueError("permissions string is invalid")

    if len(ls) != 9:
        raise ValueError("permissions string is invalid")

    perms = set()

    # User permissions
    if ls[0] == "r":
        perms.add("u_r")
    elif ls[0] != "-":
        raise ValueError("permissions string is invalid")

    if ls[1] == "w":
        perms.add("u_w")
    elif ls[1] != "-":
        raise ValueError("permissions string is invalid")

    if ls[2] in ("x", "s", "S"):
        if ls[2] in ("x", "s"):
            perms.add("u_x")
        if ls[2] in ("s", "S"):
            perms.add("setuid")
    elif ls[2] != "-":
        raise ValueError("permissions string is invalid")

    # Group permissions
    if ls[3] == "r":
        perms.add("g_r")
    elif ls[3] != "-":
        raise ValueError("permissions string is invalid")

    if ls[4] == "w":
        perms.add("g_w")
    elif ls[4] != "-":
        raise ValueError("permissions string is invalid")

    if ls[5] in ("x", "s", "S"):
        if ls[5] in ("x", "s"):
            perms.add("g_x")
        if ls[5] in ("s", "S"):
            perms.add("setguid")
    elif ls[5] != "-":
        raise ValueError("permissions string is invalid")

    # Other permissions
    if ls[6] == "r":
