@Cramers.compute.register(Settings, pd.DataFrame, dict)
def pandas_cramers_compute(
    config: Settings, df: pd.DataFrame, summary: dict
) -> Optional[pd.DataFrame]:
    threshold = config.categorical_maximum_correlation_distinct

    categorical_columns = [
        key
        for key, value in summary.items()
        if value["type"] in {"Categorical", "Boolean"}
        and 1 < value["n_distinct"] <= threshold
    ]

    if len(categorical_columns) <= 1:
        return None

    correlation_matrix = pd.DataFrame(
        np.ones((len(categorical_columns), len(categorical_columns))),
        index=categorical_columns,
        columns=categorical_columns,
    )

    for col_1_name, col_2_name in itertools.combinations(categorical_columns, 2):
        score = _pairwise_cramers(df[col_1_name], df[col_2_name])
        (
            correlation_matrix.loc[col_1_name, col_2_name],
            correlation_matrix.loc[col_2_name, col_1_name],
        ) = (score, score)

    return correlation_matrix

@Auto.compute.register(Settings, pd.DataFrame, dict)
def pandas_auto_compute(
    config: Settings, df: pd.DataFrame, summary: dict
) -> Optional[pd.DataFrame]:
    """
    This function performs automatic computation of correlations between columns in a pandas DataFrame. It first identifies the numerical and categorical columns based on the summary dictionary. Then, it discretizes the DataFrame using a uniform discretization method. Next, it calculates the correlation scores between each pair of columns using either the pairwise Spearman correlation or the pairwise Cramers' V, depending on the column types. Finally, it returns a correlation matrix.
    Input-Output Arguments
    :param config: Settings. An instance of the Settings class that contains configuration parameters.
    :param df: pd.DataFrame. The input DataFrame.
    :param summary: dict. A dictionary that summarizes the properties of each column in the DataFrame.
    :return: Optional[pd.DataFrame]. The correlation matrix if there are more than one numerical or categorical columns, otherwise None.
    """
    threshold = config.categorical_maximum_correlation_distinct

    numerical = {
        key
        for key, value in summary.items()
        if value["type"] == "Numeric" and 1 < value["n_distinct"]
    }

    categoricals = {
        key
        for key, value in summary.items()
        if value["type"] in {"Categorical", "Boolean"}
        and 1 < value["n_distinct"] <= threshold
    }

    selected_cols = sorted(
        numerical.union(categoricals), key=lambda i: list(df.columns).index(i)
    )

    if len(selected_cols) <= 1:
        return None

    matrix = np.zeros((len(selected_cols), len(selected_cols)))
    np.fill_diagonal(matrix, 1.0)
    correlation_matrix = pd.DataFrame(
        matrix, index=selected_cols, columns=selected_cols
    )

    for name1, name2 in itertools.combinations(selected_cols, 2):
        type1 = summary[name1]["type"]
        type2 = summary[name2]["type"]

        if type1 == "Numeric" and type2 == "Numeric":
            corr = _pairwise_spearman(df[name1], df[name2])
        elif type1 == "Numeric" and type2 in {"Categorical", "Boolean"}:
            corr = _pairwise_spearman(
                df[name1], pd.Series(pd.factorize(df[name2])[0], index=df.index)
            )
        elif type2 == "Numeric" and type1 in {"Categorical", "Boolean"}:
            corr = _pairwise_spearman(
                pd.Series(pd.factorize(df[name1])[0], index=df.index), df[name2]
            )
        else:
            corr = _pairwise_cramers(df[name1], df[name2])

        correlation_matrix.loc[name2, name1] = corr
        correlation_matrix.loc[name1, name2] = corr

    return correlation_matrix

