@property
def vegalite_major_version(self) -> int:
    """
    This function returns the major version number of the Vega-Lite schema used in the VegaLite instance.
    It extracts the major version number from the "$schema" attribute in the instance's data.

    :return: int. The major version number of the Vega-Lite schema used in the instance.
    """
    schema = self.data.get("$schema", "")
    if not schema:
        return 2

    # Try to find the first version-like occurrence in the schema URL/string.
    import re

    match = re.search(r"vega-lite(?:\.json)?/v?(\d+)", schema)
    if match:
        return int(match.group(1))

    # Fallback: extract the first standalone integer after "vega-lite"
    match = re.search(r"vega-lite.*?(\d+)", schema)
    if match:
        return int(match.group(1))

    return 2

