    kwonlyargs = getattr(self, 'kwonlyargs', [])
    kwonlydefaults = getattr(self, 'kwonlydefaults', {}) or {}
    required_kwonly = [arg for arg in kwonlyargs if arg not in kwonlydefaults]

    return tuple(required_args + required_kwonly)

# All positional and keyword-only args
kwonlyargs = getattr(self, 'kwonlyargs', [])
return tuple(list(self.args) + list(kwonlyargs))

