# commit to one choice, but we still check all possible choices for obvious
# conflicts.
for name_tuple in name_tuples:
    cleaned_tuple = tuple(
        item.lower() for item in name_tuple if item.lower() not in blacklist
    )
    if not cleaned_tuple:
        continue

    # Check each possible choice against everything already scheduled.
    for name in cleaned_tuple:
        conflicts = get_conflicts(name)

        # New item conflicts with something already present.
        for conflict in conflicts:
            if conflict in scheduled:
                raise BuildInterruptingException(
                    "Obvious conflict detected: '{}' conflicts with '{}' "
                    "(added by '{}').".format(
                        name, conflict, added_by.get(conflict, conflict)
                    )
                )

        # Something already present conflicts with the new item.
        for existing in list(scheduled):
            existing_conflicts = get_conflicts(existing)
            if name in existing_conflicts:
                raise BuildInterruptingException(
                    "Obvious conflict detected: '{}' conflicts with '{}' "
                    "(added by '{}').".format(
                        existing, name, added_by.get(existing, existing)
                    )
                )

    # If no conflict, mark all items in this tuple as scheduled.
    for name in cleaned_tuple:
        scheduled.add(name)
        added_by.setdefault(name, cleaned_tuple)

@classmethod
def get_bootstrap_from_recipes(cls, recipes, ctx):
    """
    Select a recommended default bootstrap from a list of recipes.

    Rules:
    - Prefer SDL2 bootstrap if any recipe depends on sdl2.
    - Prefer webview bootstrap if any recipe depends on common web recipes.
    - Otherwise choose the highest-priority acceptable bootstrap.
    """
    # First, get all bootstraps that are compatible with the requested recipes.
    usable_bootstraps = list(cls.get_usable_bootstraps_for_recipes(recipes, ctx))
    if not usable_bootstraps:
        raise BuildInterruptingException(
            "No usable bootstrap found for recipes: {}".format(recipes)
        )

    # Expand dependencies so we can inspect the full recipe set.
    expanded_recipe_lists = expand_dependencies(recipes, ctx)
    all_expanded_recipes = set()
    for recipe_list in expanded_recipe_lists:
        all_expanded_recipes.update(recipe_list)

    # Special-case preferences.
    if 'sdl2' in all_expanded_recipes:
        for bs in usable_bootstraps:
            if bs.name == 'sdl2':
                return bs

    web_recipes = {'webview', 'pyjnius', 'android', 'python3'}
    if any(r in all_expanded_recipes for r in web_recipes):
        for bs in usable_bootstraps:
            if bs.name == 'webview':
                return bs

    # Otherwise, choose by priority.
    usable_bootstraps.sort(key=functools.cmp_to_key(_cmp_bootstraps_by_priority))
    return usable_bootstraps[-1]

# Start with a single empty dependency set and progressively expand it.
expanded = [[]]

for recipe_name in recipes:
    # Try to load the recipe; if it doesn't exist, keep it as-is.
    try:
        recipe = Recipe.get_recipe(recipe_name, ctx)
    except Exception:
        recipe = None

    # Determine whether this recipe has alternative dependencies.
    alternatives = None
    if recipe is not None:
        depends = getattr(recipe, 'depends', None)
        if isinstance(depends, (tuple, list)):
            # If any dependency entry is itself a list/tuple, treat it as alternatives.
            alt_groups = [d for d in depends if isinstance(d, (tuple, list))]
            if alt_groups:
                alternatives = alt_groups

    # If there are no alternatives, just add the recipe itself.
    if not alternatives:
        for dep_list in expanded:
            if recipe_name not in dep_list:
                dep_list.append(recipe_name)
        continue

    # Otherwise, expand each current combination for every alternative choice.
    new_expanded = []
    for dep_list in expanded:
        for alt_group in alternatives:
            for alt in alt_group:
                new_list = list(dep_list)
                if alt not in new_list:
                    new_list.append(alt)
                new_expanded.append(new_list)
    expanded = new_expanded

# Remove duplicates while preserving order within each dependency list.
unique = []
seen = set()
for dep_list in expanded:
    key = tuple(sorted(dep_list))
    if key not in seen:
        seen.add(key)
        unique.append(dep_list)

return unique

