@require_capability("QUOTA")
def set_quota(self, quotas):
    """
    This function sets one or more quotas on resources in an IMAPClient instance. It takes a list of Quota objects as input and constructs the necessary arguments to set the quotas. It then sends the SETQUOTA command to the IMAP server and returns the parsed response.
    Input-Output Arguments
    :param self: IMAPClient. An instance of the IMAPClient class.
    :param quotas: List of Quota objects. The quotas to be set on resources.
    :return: No return values.
    """
    if not quotas:
        return []

    # Group quota entries by quota root, since SETQUOTA operates on a single
    # quota root at a time.
    grouped = {}
    for quota in quotas:
        grouped.setdefault(quota.quota_root, []).append(quota)

    responses = []
    for quota_root, quota_items in grouped.items():
        args = [_quote(quota_root)]
        for quota in quota_items:
            args.extend(
                [
                    _quote(quota.resource),
                    to_bytes(quota.usage),
                    to_bytes(quota.limit),
                ]
            )

        responses.append(self._raw_command_untagged(b"SETQUOTA", args, uid=False))

    return responses

