def _normalise_item(item):
    if isinstance(item, (list, tuple)):
        return [b"("] + list(
            itertools.chain.from_iterable(_normalise_item(sub) for sub in item)
        ) + [b")"]

    if isinstance(item, int):
        return [to_bytes(item)]

    if isinstance(item, (date, datetime)):
        return [to_bytes(item.strftime("%d-%b-%Y"))]

    if isinstance(item, bytes):
        if _is8bit(item):
            return [_literal(item)]
        return [item]

    if isinstance(item, str):
        if charset is None:
            encoded = item.encode("us-ascii")
        else:
            encoded = item.encode(charset)
        if _is8bit(encoded):
            return [_literal(encoded)]
        return [encoded]

    return [to_bytes(item)]

