# Build opening/closing tag events.
starts = {}
ends = {}
for e in entities:
    starts.setdefault(e.offset, []).append(e)
    ends.setdefault(e.offset + e.length, []).append(e)

result = []
last = 0

# Process positions in order, closing entities before opening new ones
# at the same offset.
positions = sorted(set(starts.keys()) | set(ends.keys()))
for pos in positions:
    if pos > len(text):
        continue

    if last < pos:
        result.append(escape(del_surrogate(text[last:pos])))
        last = pos

    # Close entities ending here, innermost first.
    for e in sorted(ends.get(pos, []), key=lambda x: x.offset, reverse=True):
        formatter = ENTITY_TO_FORMATTER.get(type(e))
        if formatter:
            close = formatter(e, del_surrogate(text[e.offset:e.offset + e.length]))[1]
            result.append(close)

    # Open entities starting here, outermost first.
    for e in sorted(starts.get(pos, []), key=lambda x: x.length, reverse=True):
        formatter = ENTITY_TO_FORMATTER.get(type(e))
        if formatter:
            open_tag = formatter(e, del_surrogate(text[e.offset:e.offset + e.length]))[0]
            result.append(open_tag)

if last < len(text):
    result.append(escape(del_surrogate(text[last:])))

# Close any entities that end at the very end.
for e in sorted(ends.get(len(text), []), key=lambda x: x.offset, reverse=True):
    formatter = ENTITY_TO_FORMATTER.get(type(e))
    if formatter:
        result.append(formatter(e, del_surrogate(text[e.offset:e.offset + e.length]))[1])

return ''.join(result)

