@classmethod
def _parse_narrow_link(cls, link: str) -> ParsedNarrowLink:
    """
    This function parses a given link and returns a dictionary with narrow
    parameters for supported links. If the link does not match any of the
    supported formats, an empty dictionary is returned.

    Supported fragments:
    a. narrow/stream/[{stream_id}-]{stream-name}
    b. narrow/stream/[{stream_id}-]{stream-name}/near/{message_id}
    c. narrow/stream/[{stream_id}-]{stream-name}/topic/{encoded.20topic.20name}
    d. narrow/stream/[{stream_id}-]{stream-name}/topic/{encoded.20topic.20name}/near/{message_id}
    """
    parsed_link: ParsedNarrowLink = {}

    # Extract the fragment after "#narrow/" if present.
    fragment = urlparse(link).fragment
    if not fragment:
        return parsed_link

    # Expected fragment starts with "narrow/".
    if not fragment.startswith("narrow/"):
        return parsed_link

    parts = fragment.split("/")
    # Minimum: narrow/stream/<stream>
    if len(parts) < 3:
        return parsed_link

    narrow_type = parts[1]
    if narrow_type != "stream":
        return parsed_link

    encoded_stream_data = parts[2]
    parsed_link["stream"] = cls._decode_stream_data(encoded_stream_data)

    # Base narrow: narrow/stream/<stream>
    if len(parts) == 3:
        parsed_link["narrow"] = "stream"
        return parsed_link

    # narrow/stream/<stream>/near/<message_id>
    if len(parts) == 5 and parts[3] == "near":
        parsed_link["narrow"] = "stream:near"
        parsed_link["message_id"] = cls._decode_message_id(parts[4])
        return parsed_link

    # narrow/stream/<stream>/topic/<topic>
    if len(parts) == 5 and parts[3] == "topic":
        parsed_link["narrow"] = "stream:topic"
        parsed_link["topic_name"] = hash_util_decode(parts[4])
        return parsed_link

    # narrow/stream/<stream>/topic/<topic>/near/<message_id>
    if len(parts) == 7 and parts[3] == "topic" and parts[5] == "near":
        parsed_link["narrow"] = "stream:topic:near"
        parsed_link["topic_name"] = hash_util_decode(parts[4])
        parsed_link["message_id"] = cls._decode_message_id(parts[6])
        return parsed_link

    return {}

