@staticmethod
def find_redirection_file_path(tokens):
    """
    This function finds the path of the file to which the output of a
    command should be redirected. It checks the tokens list to determine
    the type of redirection and returns a 2-tuple containing the
    redirection type and the file path. If no redirection is found, it
    returns None. If the redirection should be done to nowhere, it returns
    a 2-tuple with the redirection type set to "quiet" and the file path
    set to None.
    """
    if not tokens:
        return None

    # Quiet redirection: command ends with ">"
    if tokens[-1] == REDIRECTION_SYM:
        return (RedirectionType.quiet, None)

    # File redirection: command ends with ">" or ">>" followed by a path
    if len(tokens) >= 2 and tokens[-2] in (REDIRECTION_SYM, REDIRECTION_APPEND_SYM):
        redirection_type = (
            RedirectionType.append
            if tokens[-2] == REDIRECTION_APPEND_SYM
            else RedirectionType.write
        )
        return (redirection_type, tokens[-1])

    return None

@staticmethod
def get_unit_type_from_str(unit_type_str):
    """
    This function takes a string of unit_type as input and transforms it into the corresponding the value of the unit type. It checks if the input string matches any of the predefined values for UnitType and returns the corresponding value. If there is no match, it returns None.
    Input-Output Arguments
    :param unit_type_str: String. The input string to be transformed into a `UnitType` value.
    :return: UnitType. The corresponding `UnitType` value for the input string, or `None` if there is no match.
    """
    unit_type_str = unit_type_str.lower()

    # Try common unit type names directly
    for unit_type in AST.get_or_create().keys():
        if getattr(unit_type, "name", "").lower() == unit_type_str:
            return unit_type

    # Fallback: match against string representations
    for unit_type in AST.get_or_create().keys():
        if str(unit_type).lower() == unit_type_str:
            return unit_type

    return None

