@classmethod
def from_spec(cls, spec: t.Any) -> float:
    """
    This function converts a given specification to a CpuResource value. The specification can be a float, int, or string. It handles different formats of the specification and returns the corresponding CpuResource value. Note to check ValueError.
    Input-Output Arguments
    :param cls: Class. The class itself.
    :param spec: Any. The specification to be converted to CpuResource.
    :return: float. The converted CpuResource value.
    """
    if isinstance(spec, (int, float)):
        return float(spec)

    if not isinstance(spec, str):
        raise TypeError("CPU resource specification must be int, float, or str.")

    spec = spec.strip().lower()
    if not spec:
        raise BentoMLConfigException("Invalid CPU resource limit ''.")

    try:
        # Support millicpu notation, e.g. "500m" -> 0.5
        if spec.endswith("m"):
            return float(spec[:-1]) / 1000.0

        # Support plain numeric strings, e.g. "2", "1.5"
        return float(spec)
    except ValueError as err:
        raise BentoMLConfigException(f"Invalid CPU resource limit '{spec}'.") from err

@classmethod
@functools.lru_cache(maxsize=1)
def from_system(cls) -> float:
    """
    This function returns the number of CPU resources available in the system.
    It checks the operating system type and calls the appropriate function to
    retrieve the CPU count.

    :param cls: Class. The class itself.
    :return: Float. The number of CPU resources available in the system.
    """
    # Prefer cgroup-aware CPU count when available, otherwise fall back to OS count.
    cpu_count = query_cgroup_cpu_count()
    if cpu_count is not None and cpu_count > 0:
        return float(cpu_count)
    return float(query_os_cpu_count())

