@classmethod
def get_worker_env(
    cls,
    runnable_class: t.Type[Runnable],
    resource_request: dict[str, t.Any] | None,
    workers_per_resource: int | float,
    worker_index: int,
) -> dict[str, t.Any]:
    if resource_request is None:
        resource_request = system_resources()

    env: dict[str, t.Any] = {}

    # GPU workers: assign one GPU per worker in a round-robin fashion.
    nvidia_gpus = get_resource(resource_request, "nvidia.com/gpu")
    if (
        nvidia_gpus is not None
        and len(nvidia_gpus) > 0
        and "nvidia.com/gpu" in runnable_class.SUPPORTED_RESOURCES
    ):
        gpu_index = worker_index % len(nvidia_gpus)
        env["CUDA_VISIBLE_DEVICES"] = str(nvidia_gpus[gpu_index])
        return env

    # CPU workers: set thread-related env vars for multi-threaded runtimes.
    cpus = get_resource(resource_request, "cpu")
    if cpus is not None and cpus > 0:
        if runnable_class.SUPPORTS_CPU_MULTI_THREADING:
            if isinstance(workers_per_resource, float):
                raise ValueError(
                    "Fractional CPU multi threading support is not yet supported."
                )
            num_threads = workers_per_resource
        else:
            num_threads = math.ceil(cpus) * workers_per_resource

        for key in THREAD_ENVS:
            env[key] = str(num_threads)

        return env

    raise ValueError(
        f"No known supported resource available for {runnable_class}. Please check your resource request. "
        "Leaving it blank will allow BentoML to use system resources."
    )

@classmethod
def get_worker_count(
    cls,
    runnable_class: t.Type[Runnable],
    resource_request: dict[str, t.Any] | None,
    workers_per_resource: int | float,
) -> int:
    """
    This function calculates the number of workers needed based on the given parameters. It first checks if there is a resource request for Nvidia GPUs and if the runnable class supports Nvidia GPUs. If so, it calculates the number of workers based on the number of available Nvidia GPUs and the workers per resource value. If not, it checks if there are CPUs available and if the runnable class supports CPUs. If so, it calculates the number of workers based on the number of available CPUs and the workers per resource value. If none of the conditions are met, it raises a ValueError indicating that there are no known supported resources available for the runnable class.
    Input-Output Arguments
    :param cls: DefaultStrategy. The class itself.
    :param runnable_class: Type[Runnable]. The class of the runnable object.
    :param resource_request: Union[Dict[str, Any], None]. The resource request for the runnable object. Defaults to None.
    :param workers_per_resource: Union[int, float]. The number of workers per resource.
    :return: int. The number of workers needed based on the given parameters.
    """
    if resource_request is None:
        resource_request = system_resources()

    # Prefer GPU if requested and supported
    nvidia_gpus: list[int] | None = get_resource(resource_request, "nvidia.com/gpu")
    if (
        nvidia_gpus is not None
        and len(nvidia_gpus) > 0
        and "nvidia.com/gpu" in runnable_class.SUPPORTED_RESOURCES
    ):
        if isinstance(workers_per_resource, float):
            if workers_per_resource > 1:
                raise ValueError(
                    "Currently, the default strategy doesn't support workers_per_resource > 1. It is recommended that one should implement a custom strategy in this case."
                )
            assigned_resource_per_worker = round(1 / workers_per_resource)
            if assigned_resource_per_worker <= 0:
                raise ValueError(
                    f"Invalid workers_per_resource value: {workers_per_resource}"
                )
            return math.ceil(len(nvidia_gpus) / assigned_resource_per_worker)

        return len(nvidia_gpus) * int(workers_per_resource)

    # Fall back to CPU if requested and supported
    cpus = get_resource(resource_request, "cpu")
    if cpus is not None and cpus > 0 and runnable_class.SUPPORTS_CPU_MULTI_THREADING:
        if isinstance(workers_per_resource, float):
            if workers_per_resource > 1:
                raise ValueError(
                    "Currently, the default strategy doesn't support workers_per_resource > 1. It is recommended that one should implement a custom strategy in this case."
                )
            assigned_resource_per_worker = round(1 / workers_per_resource)
            if assigned_resource_per_worker <= 0:
                raise ValueError(
                    f"Invalid workers_per_resource value: {workers_per_resource}"
                )
            return math.ceil(cpus / assigned_resource_per_worker)

        return math.ceil(cpus) * int(workers_per_resource)

    if cpus is not None and cpus > 0:
        return math.ceil(cpus)

    raise ValueError(
        f"No known supported resources available for runnable class {runnable_class.__name__}."
    )

@classmethod
def to_payload(
    cls,
    batch: ext.NpNDArray,
    batch_dim: int,
) -> Payload:
    # skip 0-dimensional array
    if batch.ndim == 0:
        data = pickle.dumps(batch)
        return cls.create_payload(data=data, batch_size=1)

    # Ensure array is contiguous for efficient serialization
    if not (batch.flags.c_contiguous or batch.flags.f_contiguous):
        batch = np.ascontiguousarray(batch)

    bs: bytes
    concat_buffer_bs: bytes
    indices: list[int]
    bs, concat_buffer_bs, indices = pep574_dumps(batch)

    meta: dict[str, bool | int | float | str | list[int]] = {"format": "pickle5"}

    if indices:
        meta["with_buffer"] = True
        meta["pickle_bytes_str"] = base64.b64encode(bs).decode("ascii")
        meta["indices"] = indices
        data = concat_buffer_bs
    else:
        meta["with_buffer"] = False
        data = bs

    return cls.create_payload(
        data=data,
        batch_size=batch.shape[batch_dim],
        meta=meta,
    )

@classmethod
def batch_to_payloads(
    cls,
    batch: ext.NpNDArray,
    indices: t.Sequence[int],
    batch_dim: int = 0,
) -> list[Payload]:
    batches = cls.batch_to_batches(batch, indices, batch_dim)
    return [cls.to_payload(subbatch, batch_dim) for subbatch in batches]

@classmethod
def from_payload(
    cls,
    payload: Payload,
) -> ext.NpNDArray:
    """
    This function creates an NdarrayContainer instance from the given payload. It checks the format of the payload and if it is "pickle5", it decodes the pickle bytes and returns the deserialized ndarray. Otherwise, it uses the pickle module to load and return the deserialized ndarray.
    Input-Output Arguments
    :param cls: Class. The class itself.
    :param payload: Payload. The payload containing the data and metadata of the ndarray.
    :return: ext.NpNDArray. The deserialized ndarray.
    """
    if payload.meta.get("format") == "pickle5":
        bs_str = t.cast(str, payload.meta["pickle_bytes_str"])
        bs = base64.b64decode(bs_str)
        indices = t.cast(t.List[int], payload.meta["indices"])
        return pep574_loads(bs, payload.data, indices)

    return pickle.loads(payload.data)

@classmethod
def batch_to_payloads(
    cls,
    batch: ext.PdDataFrame,
    indices: t.Sequence[int],
    batch_dim: int = 0,
) -> list[Payload]:
    batches = cls.batch_to_batches(batch, indices, batch_dim)
    payloads = [cls.to_payload(subbatch, batch_dim) for subbatch in batches]
    return payloads

