) -> ext.PdDataFrame:
    import pandas as pd

    format = payload.meta.get("format", "default")
    if format == "pickle5":
        bs_str = t.cast(str, payload.meta["pickle_bytes_str"])
        bs = base64.b64decode(bs_str)
        indices = t.cast(t.List[int], payload.meta["indices"])

        if payload.meta.get("with_buffer", False):
            return t.cast(
                "ext.PdDataFrame",
                pep574_loads(bs, payload.data, indices),
            )

    return t.cast("ext.PdDataFrame", fixed_torch_loads(payload.data))

@classmethod
def parse_server_string(cls, server_str: str) -> Tuple[str, Optional[str], Optional[int]]:
    # Extract ip from target
    ip = None

    # If an IP is provided in curly braces, extract it first: host:port{ip}
    if "{" in server_str and "}" in server_str:
        server_str, ip_part = server_str.split("{", 1)
        ip = ip_part.split("}", 1)[0]

    # IPv6 host hint in the server string itself: [ipv6]:port
    if "[" in server_str and "]" in server_str:
        host, port = cls._parse_ipv6_server_string(server_str)
        return host, ip, port

    # IPv6 IP hint extracted from curly braces: host:port{[ipv6]}
    if ip is not None and "[" in ip and "]" in ip:
        host, port = cls._parse_ipv6_server_string(ip)
        return host, None, port

    # Default: IPv4 / hostname parsing
    host, port = cls._parse_ipv4_server_string(server_str)
    return host, ip, port

@classmethod
def result_to_console_output(cls, result: HeartbleedScanResult) -> List[str]:
    if result.is_vulnerable_to_heartbleed:
        return ["  Vulnerable to Heartbleed: YES"]
    return ["  Vulnerable to Heartbleed: NO"]

# Only consider standard HTTP redirection status codes
if http_response.status not in (301, 302, 303, 307, 308):
    return None

location = _extract_first_header_value(http_response, "location")
if not location:
    return None

# Parse the redirect target
parsed_location = urlsplit(location)

# Relative redirect: keep only the path/query/fragment
if not parsed_location.scheme and not parsed_location.netloc:
    if location.startswith("/"):
        return location
    # Handle relative paths like "login" or "../login"
    return parsed_location.path or None

# Absolute redirect: only follow if it points back to the same server
redirect_host = parsed_location.hostname
redirect_port = parsed_location.port

if redirect_host is None:
    return None

# Compare ports, accounting for default ports when not explicitly specified
if redirect_port is None:
    redirect_port = 443 if parsed_location.scheme == "https" else 80

if redirect_host.lower() != server_host_name.lower():
    return None

if redirect_port != server_port:
    return None

# Return the path, including query string and fragment if present
path = parsed_location.path or "/"
if parsed_location.query:
    path += f"?{parsed_location.query}"
if parsed_location.fragment:
    path += f"#{parsed_location.fragment}"

return path

result_txt = []

if result.supports_secure_renegotiation:
    result_txt.append("    Secure Renegotiation: supported")
else:
    result_txt.append("    Secure Renegotiation: not supported")

if result.is_vulnerable_to_client_renegotiation_dos:
    result_txt.append("    Client-initiated Renegotiation: vulnerable to DoS")
else:
    result_txt.append("    Client-initiated Renegotiation: not vulnerable to DoS")

return result_txt

try:
    san_extension = certificate.extensions.get_extension_for_oid(ExtensionOID.SUBJECT_ALTERNATIVE_NAME).value
except ExtensionNotFound:
    return SubjectAlternativeNameExtension(dns_names=[], ip_addresses=[])

dns_names: List[str] = []
ip_addresses: List[str] = []

for entry in san_extension:
    if isinstance(entry, DNSName):
        dns_names.append(entry.value)
    elif isinstance(entry, IPAddress):
        ip_addresses.append(str(entry.value))

return SubjectAlternativeNameExtension(dns_names=dns_names, ip_addresses=ip_addresses)

@classmethod
def to_payload(
    cls,
    batch: ext.PdDataFrame | ext.PdSeries,
    batch_dim: int,
) -> Payload:
    assert (
        batch_dim == 0
    ), "PandasDataFrameContainer does not support batch_dim other than 0"

    import pandas as pd

    if isinstance(batch, pd.Series):
        batch = batch.to_frame()

    # skip 0-dimensional / empty-like cases by falling back to default pickle
    if batch.shape:
        if not (batch.values.flags["C_CONTIGUOUS"] or batch.values.flags["F_CONTIGUOUS"]):
            batch = batch.copy()

        bs: bytes
        concat_buffer_bs: bytes
        indices: list[int]
        bs, concat_buffer_bs, indices = pep574_dumps(batch)
        bs_str = base64.b64encode(bs).decode("ascii")

        return cls.create_payload(
            concat_buffer_bs,
            batch.shape[batch_dim],
            {
                "format": "pickle5",
                "with_buffer": True,
                "pickle_bytes_str": bs_str,
                "indices": indices,
            },
        )

    data = pickle.dumps(batch)
    return cls.create_payload(
        data,
        batch.shape[batch_dim] if batch.shape else 0,
        {"format": "default", "with_buffer": False},
    )

@classmethod
def get_distrust_timeline(
    cls, verified_certificate_chain: List[Certificate]
) -> Optional[SymantecDistrustTimelineEnum]:

    """
    This function checks the given list of verified certificates for the presence of Symantec root certificates. It determines the distrust timeline based on the presence of blacklisted and whitelisted certificates in the chain.
    Input-Output Arguments
    :param cls: The class object of SymantecDistructTester.
    :param verified_certificate_chain: List of Certificate. A list of verified certificates.
    :return: Optional[SymantecDistrustTimelineEnum]. The distrust timeline enum value, which can be either "MARCH_2018" or "SEPTEMBER_2018", or None if no distrust is detected.
    """
    if not verified_certificate_chain:
        return None

    def _fingerprint(cert: Certificate) -> str:
        # cryptography.x509.Certificate.fingerprint() returns bytes
        return binascii.hexlify(cert.fingerprint(cert.signature_hash_algorithm)).decode("ascii").lower()

    chain_fingerprints = {_fingerprint(cert) for cert in verified_certificate_chain}

    # If any certificate in the chain is explicitly whitelisted, no distrust applies.
    if chain_fingerprints.intersection(cls._CA_KEYS_WHITELIST):
        return None

    # If any certificate in the chain is blacklisted, it is distrusted starting March 2018.
    if chain_fingerprints.intersection(cls._CA_KEYS_BLACKLIST):
        return SymantecDistrustTimelineEnum.MARCH_2018

    return None

try:
    # Build the dict format expected by ssl.match_hostname from the certificate subject and SANs.
    cert_dict = {
        "subject": tuple(
            tuple((attr.oid._name or attr.oid.dotted_string, attr.value) for attr in rdn)
            for rdn in certificate.subject.rdns
        )
    }

    try:
        san = certificate.extensions.get_extension_for_oid(ExtensionOID.SUBJECT_ALTERNATIVE_NAME).value
        cert_dict["subjectAltName"] = [("DNS", name) for name in san.get_values_for_type(cryptography.x509.DNSName)]
    except ExtensionNotFound:
        pass

    match_hostname(cert_dict, server_hostname)
    return True
except CertificateError:
    return False

common_names = name_field.get_attributes_for_oid(x509.NameOID.COMMON_NAME)
if common_names:
    return common_names[0].value
return name_field.rfc4514_string()

@classmethod
def batch_to_payloads(
    cls,
    batch: list[t.Any],
    indices: t.Sequence[int],
    batch_dim: int = 0,
) -> list[Payload]:
    batches = cls.batch_to_batches(batch, indices, batch_dim)
    return [cls.to_payload(subbatch, batch_dim) for subbatch in batches]
